import logging
from azure.storage.blob import BlobServiceClient
from azure.functions import HttpRequest, Function

def main(req: HttpRequest) -> str:
    try:
        # Get blob path from query parameter
        blob_path = req.params.get('path')

        # Instantiate BlobServiceClient
        blob_service_client = BlobServiceClient.from_connection_string('<your_connection_string>')

        # Construct blob client
        blob_client = blob_service_client.get_blob_client(container='<your_container_name>', blob=blob_path)

        # Read blob content
        blob_data = blob_client.download_blob().readall()

        # Return blob content as string
        return blob_data.decode('utf-8')

    except Exception as ex:
        logging.error(ex)
        return str(ex)